import React, { useEffect, useState } from 'react'
import { useParams, Link } from 'react-router-dom';
import axios from 'axios'

import './ProductScreen.css'
import Rating from '../components/Rating'
import ProductsList from '../components/ProductsList'


function ProductScreen() {
    const { id } = useParams();
    const [product, setProduct] = useState();
    const [qty, setQty] = useState(0);
    const [relatedProducts, setRelatedProducts] = useState([]);

    console.log(id);

    const fetchProduct = async () => {
      const { data } = await axios.get('api/products/1/');
      setProduct(data);
    }

    useEffect(() => {
      console.log('+++++++++')

  
      fetchProduct();
      
    }, [product, id])

    // useEffect( () => {
    //   async function fetchRelatedProducts() {
    //     const { data } = await axios.get('http://127.0.0.1:8000/api/products/');
    //     setRelatedProducts(data.slice(0, 4));
    //   }
    //   fetchRelatedProducts();
    // }, []);

    console.log(product);

    let inStock = true;
    // set default quantity to 1 if the product is in stock
    // let inStock = (product.countInStock > 0);
    useEffect(() => {
        console.log("jsdic jsdoid")
        if(inStock) setQty(1);
    }, [inStock,]);

  return (
    <div>
      <div className='breadcrumbs'>
        <Link to='/'>Home</Link>/
        <Link to={product.category}>{product.category}</Link>/
        {product.name}
      </div>

      <div className='product'>

        <div className='left'>
            <img src={product.image}></img>
        </div>

        <div className='right'>
            <div className='name'>{product.name}</div>
            <Rating className='rating' value={product.rating} text={`(${product.numReviews})`} />
            <p className='price'>{product.price}&euro; - <span>{inStock ? <>In</> : <>Out of</>} Stock</span></p>
            <div className='qty'>
                <label>Quantity:</label>
                <select value={qty} onChange={(e) => setQty(e.target.value)}>
                    {[...new Array(product.countInStock+1).keys()]
                    .map((val) => {
                        return (<option key={val} value={val}>{val}</option>)
                    })}
                </select>
                
            </div>
            <p className='total'>Total: {qty * product.price}&euro;</p>
            <div className='add-product'>
                <button disabled={inStock ? false : true} className='cart'>Add to cart</button>
                <button className='wishlist'><i className='far fa-heart'/>&nbsp;&nbsp;Add to wishlist</button>
            </div>
            <p className='brand'>Brand: {product.brand.toUpperCase()}</p>
            <p className='desc'>{product.description}</p>
        </div>

      </div>

      {/* <div className='related-products'>
        <h1 className='title'>Related products</h1>
        <ProductsList products={relatedProducts} />
      </div> */}
    </div>
  )
}

export default ProductScreen;
